head.script:
            scwin.onpageload = function() {
                scwin.loadFolders();
            };

            scwin.callApi = function(url, callback) {
                var xhr = new XMLHttpRequest();
                xhr.open("GET", url, true);
                xhr.onreadystatechange = function() {
                   if (xhr.readyState !== 4) { return; }
                    if (xhr.status >= 200 && xhr.status < 300) {
                        try {
                            callback(JSON.parse(xhr.responseText || "[]"));
                        } catch (e) {
                            console.error("[FileBrowser] JSON parse error", url, e);
                            callback([]);
                        }
                        } else {
                        console.error("[FileBrowser] HTTP error", xhr.status, url);
                        callback([]);
                    }
                };
                xhr.onerror = function() {
                    console.error("[FileBrowser] Network error", url);
                    callback([]);
                };
                xhr.send();
            };

            scwin.callApiJson = function(method, url, payload, callback) {
                var xhr = new XMLHttpRequest();
                xhr.open(method, url, true);
                xhr.setRequestHeader("Content-Type", "application/json; charset=UTF-8");
                xhr.onreadystatechange = function() {
                    if (xhr.readyState !== 4) { return; }
                    if (xhr.status >= 200 && xhr.status < 300) {
                        callback(JSON.parse(xhr.responseText || "{}"));
                    } else {
                        alert("Lưu thất bại. HTTP " + xhr.status);
                    }
                };
                xhr.send(JSON.stringify(payload || {}));
            };

            scwin._formatFileSize = function(bytes) {
                var n = parseFloat(bytes || 0);
                if (!n || n <= 0) { return "0 B"; }
                var kb = 1024;
                var mb = kb * 1024;
                var gb = mb * 1024;
                if (n >= gb) { return (n / gb).toFixed(2) + " GB"; }
                if (n >= mb) { return (n / mb).toFixed(2) + " MB"; }
                if (n >= kb) { return (n / kb).toFixed(2) + " KB"; }
                return n + " B";
            };

            scwin._setDetailField = function(compId, key, value) {
                var val = value == null ? "" : String(value);
                dmAssetDetail.set(key, val);
                try {
                    var comp = $p.getComponentById(compId);
                    if (comp && typeof comp.setValue === "function") {
                        comp.setValue(val);
                    }
                } catch (e) {}
            };

            scwin._clearAssetDetail = function() {
                 scwin._setDetailField("inpFileNm", "FILE_NM", "");
                scwin._setDetailField("taDescription", "DESCRIPTION", "");
                scwin._setDetailField("inpFileType", "FILE_TYPE", "");
                scwin._setDetailField("inpTags", "TAGS", "");
                scwin._setDetailField("selAssetData", "ASSET_DATA", "Draft");
                scwin._setDetailField("inpFileSize", "FILE_SIZE", "");
                scwin._setDetailField("inpOwnerNm", "OWNER_NM", "");
                scwin._setDetailField("inpUploadDt", "UPLOAD_DT", "");
            };

            scwin._realRowIndex = function(displayRow) {
                if (displayRow == null || displayRow < 0) { return -1; }
                try {
                    var grd = $p.getComponentById("grdAsset");
                    if (grd && typeof grd.getRealRowIndex === "function") {
                        return grd.getRealRowIndex(displayRow);
                    }
                } catch (e) {}
                return displayRow;
            };

            scwin._applyDetailFromGridRow = function(rowData) {
                if (!rowData) { return; }
                var st = rowData.STATUS || "Draft";
                if (st !== "Draft" && st !== "Published" && st !== "Archived") { st = "Draft"; }
                scwin._setDetailField("inpFileNm", "FILE_NM", rowData.FILE_NM || "");
                scwin._setDetailField("inpFileType", "FILE_TYPE", rowData.FILE_TYPE || "");
                scwin._setDetailField("inpFileSize", "FILE_SIZE", rowData.FILE_SIZE || "");
                scwin._setDetailField("selAssetData", "ASSET_DATA", st);
                scwin._setDetailField("inpOwnerNm", "OWNER_NM", rowData.OWNER_NM || "");
                scwin._setDetailField("inpUploadDt", "UPLOAD_DT", rowData.UPLOAD_DT || "");
            };

            scwin._selectRowAndShowDetail = function(displayRowIndex) {
                var ri = scwin._realRowIndex(displayRowIndex);
                if (ri < 0) { return; }
                var rowData = dlAsset.getRowJSON(ri);
                if ((!rowData || rowData.ASSET_ID == null || rowData.ASSET_ID === "") && displayRowIndex >= 0) {
                    rowData = dlAsset.getRowJSON(displayRowIndex);
                }
                if (!rowData || rowData.ASSET_ID == null || rowData.ASSET_ID === "") { return; }
                scwin._applyDetailFromGridRow(rowData);
                scwin.loadAssetDetail(rowData.ASSET_ID, rowData);
                try {
                    var grd = $p.getComponentById("grdAsset");
                    if (grd && typeof grd.setSelectedIndex === "function") {
                        grd.setSelectedIndex(displayRowIndex);
                    }
                 } catch (e) {}
	            };

	            scwin._buildFolderRows = function(folders) {
	                var list = folders || [];
	                var childrenMap = {};
	                var allIds = {};
	                for (var i = 0; i < list.length; i++) {
	                    var id = list[i].folderId != null ? list[i].folderId : list[i].FOLDER_ID;
	                    allIds[id] = true;
	                }
	                for (var j = 0; j < list.length; j++) {
	                    var item = list[j];
	                    var pid = item.parentFolderId != null ? item.parentFolderId : item.PARENT_FOLDER_ID;
	                    if (!pid) { pid = 0; }
	                    if (!childrenMap[pid]) { childrenMap[pid] = []; }
	                    childrenMap[pid].push(item);
	                }
	                var roots = [];
	                for (var k = 0; k < list.length; k++) {
	                    var f = list[k];
	                    var parentId = f.parentFolderId != null ? f.parentFolderId : f.PARENT_FOLDER_ID;
	                    if (!parentId || !allIds[parentId]) { roots.push(f); }
	                }
	                var rows = [];
	                var visit = function(node, depth) {
	                    var nodeId = node.folderId != null ? node.folderId : node.FOLDER_ID;
	                    rows.push({
	                        FOLDER_ID: String(nodeId),
	                        FOLDER_NM: node.folderNm || node.FOLDER_NM || "",
	                        DEPTH: String(depth)
	                    });
	                    var children = childrenMap[nodeId] || [];
	                    for (var n = 0; n < children.length; n++) {
	                        visit(children[n], depth + 1);
	                    }
	                };
	                for (var r = 0; r < roots.length; r++) { visit(roots[r], 1); }
	                return rows;
	            };
	            scwin.buildFolderRows = scwin._buildFolderRows;

            scwin.loadFolders = function() {
                scwin.callApi("/api/dam/folders", function(folders) {
                    if (!folders || !folders.length) {
                     dlFolder.setJSON([]);
                        dlAsset.setJSON([]);
                        scwin._clearAssetDetail();
                        return;
                    }
                                        var buildRowsFn = (typeof scwin._buildFolderRows === "function")
	                        ? scwin._buildFolderRows
	                        : (typeof scwin.buildFolderRows === "function" ? scwin.buildFolderRows : null);
	                    if (typeof buildRowsFn !== "function") {
	                        console.error("[FileBrowser] buildFolderRows function is missing");
	                        dlFolder.setJSON([]);
	                        return;
	                    }
	                    var rows = buildRowsFn(folders);
                    dlFolder.setJSON(rows);
                    window.setTimeout(function() {
                        try { trvFolder.expandAll(); } catch (e) {}
                    }, 100);

                    scwin._loadFirstFolderWithAssets(folders, 0);
                });
            };

            scwin._loadFirstFolderWithAssets = function(folders, index) {
                if (!folders || index >= folders.length) {
                    dlAsset.setJSON([]);
                    scwin._clearAssetDetail();
                    return;
                }
                var folder = folders[index];
                var folderId = folder.folderId != null ? folder.folderId : folder.FOLDER_ID;
                if (folderId == null) {
                    scwin._loadFirstFolderWithAssets(folders, index + 1);
                    return;
                }
                scwin.callApi("/api/dam/assets?folderId=" + encodeURIComponent(folderId), function(list) {
                    if (list && list.length > 0) {
                        dmFolder.set("FOLDER_ID", String(folderId));
                        dmFolder.set("FOLDER_NM", folder.folderNm || folder.FOLDER_NM || "");
                        scwin.loadAssets(folderId);
                    } else {
                        scwin._loadFirstFolderWithAssets(folders, index + 1);
                    }
                });
            };

            scwin.loadAssets = function(folderId) {
                scwin.callApi("/api/dam/assets?folderId=" + encodeURIComponent(folderId), function(list) {
                    var rows = [];
                    for (var i = 0; i < (list || []).length; i++) {
                        var item = list[i];
                        rows.push({
                            "ASSET_ID": item.assetId,
                            "ICON": item.fileExt ? String(item.fileExt).toUpperCase() : (item.fileType || ""),
                            "FILE_NM": item.fileNm || "",
                            "FILE_TYPE": item.fileType || "",
                            "FILE_SIZE": scwin._formatFileSize(item.fileSize),
                            "STATUS": item.status || "Draft",
                            "OWNER_NM": item.ownerNm || "",
                            "UPLOAD_DT": item.uploadDt || ""
                        });
                    }
                    dlAsset.setJSON(rows);
                    if (rows.length > 0) {
                        scwin._applyDetailFromGridRow(rows[0]);
                        scwin.loadAssetDetail(rows[0].ASSET_ID, rows[0]);
                        window.setTimeout(function() {
                            try {
                                var grd = $p.getComponentById("grdAsset");
                                if (grd && typeof grd.setSelectedIndex === "function") {
                                    grd.setSelectedIndex(0);
                                }
                            } catch (e) {}
                        }, 50);
                    } else {
                        scwin._clearAssetDetail();
                    }
                });
            };

              scwin.trvFolder_onclick = function() {
                var folderId = parseInt(trvFolder.getSelectedValue(), 10);
                if (isNaN(folderId)) { return; }
                dmFolder.set("FOLDER_ID", String(folderId));
                scwin.loadAssets(folderId);
            };

            scwin._normalizeRowIndex = function(rowLike) {
                var row = rowLike;
                if (row && typeof row === "object") {
                    if (typeof row.rowIndex === "number") { row = row.rowIndex; }
                    else if (typeof row.newRowIndex === "number") { row = row.newRowIndex; }
                    else if (typeof row.index === "number") { row = row.index; }
                }
                row = parseInt(row, 10);
                if (isNaN(row) || row < 0) { return -1; }
                return row;
            };
            scwin.grdAsset_onrowindexchange = function(row, oldRow) {
                 var newRow = scwin._normalizeRowIndex(row);
                if (newRow < 0 && arguments.length >= 3) {
                    newRow = scwin._normalizeRowIndex(arguments[2]);
                }
                if (newRow < 0) { return; }
                scwin._selectRowAndShowDetail(newRow);
            };

            /* Khi focus ô đổi hàng (chuột / phím), đồng bộ panel phải */
            scwin.grdAsset_oncellindexchange = function(row, col, oldRow, oldCol) {
                 var newRow = scwin._normalizeRowIndex(row);
                var prevRow = scwin._normalizeRowIndex(oldRow);
                if (newRow < 0 && arguments.length >= 3) {
                    prevRow = scwin._normalizeRowIndex(arguments[1]);
                    newRow = scwin._normalizeRowIndex(arguments[2]);
                }
                if (newRow < 0 || newRow === prevRow) { return; }
                scwin._selectRowAndShowDetail(newRow);
            };

            scwin.grdAsset_oncellclick = function(row, col, colId) {
                var newRow = scwin._normalizeRowIndex(row);
                if (newRow < 0 && arguments.length >= 2) {
                    newRow = scwin._normalizeRowIndex(arguments[1]);
                }
                if (newRow < 0) { return; }
                if (colId && String(colId).indexOf("hd") === 0) { return; }
                  scwin._selectRowAndShowDetail(newRow);
                try {
                    var rowData = dlAsset.getRowJSON(scwin._realRowIndex(newRow));
                    if (rowData && rowData.ASSET_ID) {
                        scwin.openAssetPopup(Number(rowData.ASSET_ID));
                    }
                } catch (e) {
                    console.warn("[FileBrowser] oncellclick popup open", e);
                }
            };

            scwin.loadAssetDetail = function(assetId, fallbackRow) {
                scwin.callApi("/api/dam/assets/" + encodeURIComponent(assetId), function(response) {
                    var base = fallbackRow || {};
                    if (!response || !response.asset) {
                        scwin._applyDetailFromGridRow(base);
                          scwin._setDetailField("taDescription", "DESCRIPTION", "");
                        scwin._setDetailField("inpTags", "TAGS", "");
                        return;
                    }
                    var asset = response.asset;
                    var status = asset.status || base.STATUS || "Draft";
                    if (status !== "Draft" && status !== "Published" && status !== "Archived") {
                        status = "Draft";
                    }
                    scwin._setDetailField("inpFileNm", "FILE_NM", asset.fileNm || base.FILE_NM || "");
                    scwin._setDetailField("taDescription", "DESCRIPTION", asset.description || "");
                    scwin._setDetailField("inpFileType", "FILE_TYPE", asset.fileType || base.FILE_TYPE || "");
                    scwin._setDetailField("inpTags", "TAGS", asset.tags || "");
                    scwin._setDetailField("selAssetData", "ASSET_DATA", status);
                    var sz = "";
                    if (asset.fileSize != null && typeof asset.fileSize === "number") {
                        sz = scwin._formatFileSize(asset.fileSize);
                    } else {
                        sz = base.FILE_SIZE || "";
                    }
                    scwin._setDetailField("inpFileSize", "FILE_SIZE", sz);
                    scwin._setDetailField("inpOwnerNm", "OWNER_NM", asset.ownerNm || base.OWNER_NM || "");
                    scwin._setDetailField("inpUploadDt", "UPLOAD_DT", asset.uploadDt || base.UPLOAD_DT || "");
                });
            };

            scwin.grdAsset_oncelldblclick = function(row, col, colId) {
                try {
                    var grd = $p.getComponentById("grdAsset");
                    if (!grd) { return; }
                    var ri = grd.getRealRowIndex(row);
                    var rowData = dlAsset.getRowJSON(ri);
                    if (rowData && rowData.ASSET_ID) {
                        scwin.openAssetPopup(Number(rowData.ASSET_ID));
                    }
                } catch (e) {
                    console.warn("[FileBrowser] oncelldblclick", e);
                }
            };

            scwin.openAssetPopup = function(assetId) {
                if (!assetId) { return; }
                 scwin._openInlineUploadPopup({ assetId: assetId });
            };

            scwin._applyPopupPreview = function(url) {
                var u = url || "/cm/dam/images/preview/document.svg";
                try {
                    var img = $p.getComponentById("img_fb_popup_preview");
                    if (img && typeof img.setSrc === "function") { img.setSrc(u); }
                } catch (e) {}
            };

            scwin._suggestNextVerNo = function(latestVer) {
                var v = (latestVer || "").trim();
                if (!v) { return "v1.0"; }
                var m = v.match(/^(v?)(\d+(?:\.\d+)?)$/i);
                if (m) {
                     var prefix = (m[1] === "V" ? "V" : "v");
                    var n = parseFloat(m[2]);
                    if (!isNaN(n)) {
                        return prefix + (Math.round((n + 0.1) * 10) / 10).toFixed(1);
                    }
                }
                return v + ".1";
            };

            scwin._openInlineUploadPopup = function(param) {
                var assetId = param && (param.assetId != null ? param.assetId : param.ASSET_ID);
                dmPopup.set("ASSET_ID", assetId ? String(assetId) : "");
                dmPopup.set("VER_ID", "");
                dmPopup.set("FILE_NM", "");
                dmPopup.set("NEW_VER_NO", "v1.0");
                dmPopup.set("UPLOAD_FILE_NM", "");
                dmPopup.set("CONTRIBUTORS", "Carol");
                dmPopup.set("CHANGE_NOTES", "");
                dmPopup.set("PREVIEW_URL", "/cm/dam/images/preview/document.svg");
                scwin._applyPopupPreview(dmPopup.get("PREVIEW_URL"));
                $p.getComponentById("txt_fb_popup_title").setLabel("Upload New Version");

                if (assetId) {
                    scwin.callApi("/api/dam/assets/" + encodeURIComponent(assetId), function(res) {
                        if (!res || !res.asset) { return; }
                        var a = res.asset;
                        var latest = (res.versions || [])[0] || null;
                          var latestVer = latest ? latest.verNo : "v1.0";
                        var preview = (latest && latest.previewUrl) ? latest.previewUrl : (a.previewUrl || "/cm/dam/images/preview/document.svg");
                        dmPopup.set("ASSET_ID", String(a.assetId != null ? a.assetId : ""));
                        dmPopup.set("VER_ID", latest && latest.verId != null ? String(latest.verId) : "");
                        dmPopup.set("FILE_NM", a.fileNm || "");
                        dmPopup.set("NEW_VER_NO", scwin._suggestNextVerNo(latestVer));
                        dmPopup.set("CONTRIBUTORS", a.ownerNm || "Carol");
                        dmPopup.set("CHANGE_NOTES", (latest && latest.changeLog) ? latest.changeLog : "");
                        dmPopup.set("PREVIEW_URL", preview);
                        $p.getComponentById("txt_fb_popup_title").setLabel("Upload New Version: " + (a.fileNm || ""));
                        scwin._applyPopupPreview(preview);
                    });
                }
                var bg = document.getElementById("fbPopupBackdrop");
                if (bg) { bg.style.display = "block"; }
            };

            scwin.btn_fb_browse_onclick = function() {
                dmPopup.set("UPLOAD_FILE_NM", dmPopup.get("FILE_NM") || "");
            };

            scwin.btn_fb_cancel_onclick = function() {
                var bg = document.getElementById("fbPopupBackdrop");
                if (bg) { bg.style.display = "none"; }
            };

            scwin.btn_fb_submit_onclick = function() {
                var assetId = dmPopup.get("ASSET_ID");
                var verId = dmPopup.get("VER_ID");
                if (!assetId) {
                    alert("Không tìm thấy asset để cập nhật.");
                    return;
                }
                var payload = {
                    verNo: dmPopup.get("NEW_VER_NO") || "",
                    ownerNm: dmPopup.get("CONTRIBUTORS") || "",
                    changeLog: dmPopup.get("CHANGE_NOTES") || "",
                    previewUrl: dmPopup.get("PREVIEW_URL") || "",
                    fileUrl: dmPopup.get("UPLOAD_FILE_NM") || dmPopup.get("FILE_NM") || ""
                };
                  var method = verId ? "PUT" : "POST";
                var url = verId
                    ? ("/api/dam/assets/" + encodeURIComponent(assetId) + "/versions/" + encodeURIComponent(verId))
                    : ("/api/dam/assets/" + encodeURIComponent(assetId) + "/versions");
                scwin.callApiJson(method, url, payload, function() {
                    alert(verId ? "Cập nhật version thành công." : "Tạo version thành công.");
                    scwin.btn_fb_cancel_onclick();
                    scwin.loadAssetsByFolder();
                });
            };
